use strict;
use warnings;
use lib "c:\\bat";
use set4nt;

my @batch;

push( @batch, <<EOF
\@echo off
rm -rf package bin64
mkdir package bin64
iff %WSQLVER% == 17.0 .OR. %WSQLVER% == 17.1 then
   set _src=%SQLANY17%
elseiff %WSQLVER% == 16.0 then
   set _src=%SQLANY16%
else
   echo Unknown WSQLVER %WSQLVER%
   goto done
endiff

copy %_src%\\Node\\sqlanywhere\\bin64\\sqlany*.node bin64\\
copy binding.gyp package\\
copy build.js package\\
copy package.json package\\
copy README.md package\\
xcopy /e/q bin64 package\\bin64\\
xcopy /e/q lib package\\lib\\
xcopy /e/q src package\\src\\
pushd package\\src
rm -f amd* nt* Jamfile *.out *.js
popd
EOF
    );

# Now read the version number from package.json
open( JSON, "package.json" ) || die "Can't read package.json: $!\n";
my $ver = "unknown";
while( <JSON> ) {
    if( /version\":\s*\"(.*)\",?/ ) {
	$ver = $1;
	last;
    }
}
close( JSON );
die "Can't find version in package.json\n" if $ver eq "unknown";

push( @batch, <<EOF
if exist sqlanywhere-$ver.tar del sqlanywhere-$ver.tar
tar cf sqlanywhere-$ver.tar package
if exist sqlanywhere-$ver.tar.tgz del sqlanywhere-$ver.tar.tgz
gzip -S .tgz sqlanywhere-$ver.tar
if exist sqlanywhere-$ver.tgz del sqlanywhere-$ver.tgz
rename sqlanywhere-$ver.tar.tgz sqlanywhere-$ver.tgz

:done
EOF
    );

#print @batch;
set4nt::execute( \@batch );
